import { Authorization } from '@/constants/authorization';
import api from '@/utils/api';
import { getAuthorization } from '@/utils/authorization-util';
import axios from 'axios';

type ApiResult<T> = {
  code: number;
  message: string;
  data: T;
};

type StartResult = {
  job_id: string;
  status: string;
  elapsed_seconds: number;
  timeout_limit_seconds: number;
  output_name: string;
  pipeline?: {
    date_filter_applied?: boolean;
    narrative_records_extracted?: number;
    date_range?: { start: string; end: string; column_hint?: string | null };
  };
};

function assertApiOk<T>(body: ApiResult<T>, fallbackMessage: string): T {
  if (body?.code !== 0 || body.data === undefined || body.data === null) {
    throw new Error(body?.message || fallbackMessage);
  }
  return body.data;
}

export async function createFormFillJob(): Promise<string> {
  const { data } = await axios.post<ApiResult<{ job_id: string }>>(
    api.formFillCreateJob,
    {},
    {
      headers: {
        [Authorization]: getAuthorization(),
      },
    },
  );
  const payload = assertApiOk(data, 'Failed to create job');
  if (!payload.job_id) {
    throw new Error(data.message || 'Failed to create job: missing job_id');
  }
  return payload.job_id;
}

export async function uploadFormFillSources(jobId: string, files: File[]) {
  const formData = new FormData();
  files.forEach((file) => formData.append('source', file));
  const { data } = await axios.post<ApiResult<{ job_id: string; sources: string[] }>>(
    api.formFillUploadSources(jobId),
    formData,
    {
      headers: {
        [Authorization]: getAuthorization(),
      },
    },
  );
  return assertApiOk(data, 'Failed to upload sources');
}

