export async function startFormFill(jobId: string, userRequirements?: string) {
  const body =
    userRequirements && userRequirements.trim()
      ? { user_requirements: userRequirements.trim() }
      : {};
  const { data } = await axios.post<ApiResult<StartResult>>(
    api.formFillStart(jobId),
    body,
    {
      headers: {
        [Authorization]: getAuthorization(),
      },
    },
  );
  return assertApiOk(data, 'Failed to start form fill');
}

export async function evaluateFormFill(jobId: string) {
  const { data } = await axios.post<
    ApiResult<{
      job_id: string;
      accuracy: number;
      matched_cells: number;
      total_cells: number;
      pass_80: boolean;
      mismatches: Array<{ position: string; expected: string; actual: string }>;
    }>
  >(api.formFillEvaluate(jobId), {}, {
    headers: {
      [Authorization]: getAuthorization(),
    },
  });
  return assertApiOk(data, 'Failed to evaluate form fill');
}

export async function downloadFormFillResult(jobId: string) {
  const response = await axios.get(api.formFillDownload(jobId), {
    responseType: 'blob',
    headers: {
      [Authorization]: getAuthorization(),
    },
  });
  const disposition = response.headers?.['content-disposition'] as string | undefined;
  let filename = '';
  if (disposition) {
    const m = disposition.match(/filename\*?=(?:UTF-8''|")?([^";]+)/i);
    if (m?.[1]) {
      filename = decodeURIComponent(m[1]).replace(/"/g, '').trim();
    }
  }
  return { blob: response.data as Blob, filename };
}

export async function removeFormFillJob(jobId: string) {
  const { data } = await axios.delete<ApiResult<{ job_id: string; deleted: boolean }>>(
    api.formFillDelete(jobId),
    {
      headers: {
        [Authorization]: getAuthorization(),
      },
    },
  );
  assertApiOk(data, 'Failed to delete job');
}
