import message from '@/components/ui/message';
import { Button } from '@/components/ui/button';
import { Textarea } from '@/components/ui/textarea';
import {
  createFormFillJob,
  downloadFormFillResult,
  evaluateFormFill,
  removeFormFillJob,
  startFormFill,
  uploadFormFillReference,
  uploadFormFillSources,
  uploadFormFillTemplate,
} from '@/services/form-fill-service';
import { useCallback, useMemo, useState } from 'react';
import { useTranslation } from 'react-i18next';

const sourceAccept = '.docx,.xlsx,.md,.txt';
const templateAccept = '.docx,.xlsx';
const referenceAccept = '.docx,.xlsx';

export default function FormFillPage() {
  const { t } = useTranslation();
  const [jobId, setJobId] = useState('');
  const [sourceFiles, setSourceFiles] = useState<File[]>([]);
  const [templateFile, setTemplateFile] = useState<File | null>(null);
  const [loading, setLoading] = useState(false);
  const [referenceFile, setReferenceFile] = useState<File | null>(null);
  const [userRequirements, setUserRequirements] = useState('');
  const [startResult, setStartResult] = useState<{
    elapsedSeconds: number;
    timeoutLimitSeconds: number;
    outputName?: string;
    pipeline?: {
      date_filter_applied?: boolean;
      narrative_records_extracted?: number;
      date_range?: { start: string; end: string; column_hint?: string | null };
    };
  } | null>(null);
  const [evalResult, setEvalResult] = useState<{
    accuracy: number;
    matchedCells: number;
    totalCells: number;
    pass80: boolean;
  } | null>(null);

  const canStart = useMemo(() => {
    return Boolean(jobId && sourceFiles.length > 0 && templateFile && !loading);
  }, [jobId, sourceFiles.length, templateFile, loading]);

  const handleCreateJob = useCallback(async () => {
    try {
      setLoading(true);
      const id = await createFormFillJob();
      setJobId(id);
      setStartResult(null);
      setEvalResult(null);
      setUserRequirements('');
      message.success(t('formFill.messages.jobCreated'));
    } catch (e: any) {
      message.error(e?.message || t('formFill.messages.createJobFailed'));
    } finally {
      setLoading(false);
    }
  }, [t]);

  const handleUploadSources = useCallback(async () => {
    if (!jobId) {
      message.warning(t('formFill.messages.createJobFirst'));
      return;
    }
    if (!sourceFiles.length) {
      message.warning(t('formFill.messages.selectSources'));
      return;
    }
    try {
      setLoading(true);
      await uploadFormFillSources(jobId, sourceFiles);
      message.success(t('formFill.messages.sourcesUploaded'));
    } catch (e: any) {
      message.error(e?.message || t('formFill.messages.uploadSourcesFailed'));
    } finally {
      setLoading(false);
    }
  }, [jobId, sourceFiles, t]);

  const handleUploadTemplate = useCallback(async () => {
    if (!jobId) {
      message.warning(t('formFill.messages.createJobFirst'));
      return;
    }
    if (!templateFile) {
      message.warning(t('formFill.messages.selectTemplate'));
      return;
    }
    try {
      setLoading(true);
      await uploadFormFillTemplate(jobId, templateFile);
      message.success(t('formFill.messages.templateUploaded'));
    } catch (e: any) {
      message.error(e?.message || t('formFill.messages.uploadTemplateFailed'));
    } finally {
      setLoading(false);
    }
  }, [jobId, templateFile, t]);

  const handleStart = useCallback(async () => {
    if (!canStart) {
      message.warning(t('formFill.messages.checkInputs'));
      return;
    }
    try {
      setLoading(true);
      const result = await startFormFill(jobId, userRequirements);
      setStartResult({
        elapsedSeconds: result.elapsed_seconds,
        timeoutLimitSeconds: result.timeout_limit_seconds,
        outputName: result.output_name,
        pipeline: result.pipeline,
      });
      setEvalResult(null);
      message.success(t('formFill.messages.started'));
    } catch (e: any) {
      message.error(e?.message || t('formFill.messages.startFailed'));
    } finally {
      setLoading(false);
    }
  }, [canStart, jobId, userRequirements, t]);

  const handleDownload = useCallback(async () => {
    if (!jobId) {
      message.warning(t('formFill.messages.createJobFirst'));
      return;
    }
    try {
      setLoading(true);
      const { blob, filename } = await downloadFormFillResult(jobId);
      const link = document.createElement('a');
      const url = URL.createObjectURL(blob);
      link.href = url;
      const fallbackSuffix = templateFile?.name.endsWith('.docx') ? '.docx' : '.xlsx';
      link.download =
        filename || startResult?.outputName || `filled_template_${jobId}${fallbackSuffix}`;
      document.body.appendChild(link);
      link.click();
      link.remove();
      URL.revokeObjectURL(url);
      message.success(t('formFill.messages.downloaded'));
    } catch (e: any) {
      message.error(e?.message || t('formFill.messages.downloadFailed'));
    } finally {
      setLoading(false);
    }
  }, [jobId, startResult?.outputName, t, templateFile?.name]);

  const handleUploadReference = useCallback(async () => {
    if (!jobId) {
      message.warning(t('formFill.messages.createJobFirst'));
      return;
    }
    if (!referenceFile) {
      message.warning(t('formFill.messages.selectReference'));
      return;
    }
    try {
      setLoading(true);
      await uploadFormFillReference(jobId, referenceFile);
      message.success(t('formFill.messages.referenceUploaded'));
    } catch (e: any) {
      message.error(e?.message || t('formFill.messages.uploadReferenceFailed'));
    } finally {
      setLoading(false);
    }
  }, [jobId, referenceFile, t]);

  const handleEvaluate = useCallback(async () => {
    if (!jobId) {
      message.warning(t('formFill.messages.createJobFirst'));
      return;
    }
    try {
      setLoading(true);
      const data = await evaluateFormFill(jobId);
      setEvalResult({
        accuracy: data.accuracy,
        matchedCells: data.matched_cells,
        totalCells: data.total_cells,
        pass80: data.pass_80,
      });
      message.success(t('formFill.messages.evaluated'));
    } catch (e: any) {
      message.error(e?.message || t('formFill.messages.evaluateFailed'));
    } finally {
      setLoading(false);
    }
  }, [jobId, t]);

  const handleCleanup = useCallback(async () => {
    if (!jobId) {
      return;
    }
    try {
      setLoading(true);
      await removeFormFillJob(jobId);
      setJobId('');
      setTemplateFile(null);
      setReferenceFile(null);
      setSourceFiles([]);
      setUserRequirements('');
      setStartResult(null);
      setEvalResult(null);
      message.success(t('formFill.messages.cleaned'));
    } catch (e: any) {
      message.error(e?.message || t('formFill.messages.cleanupFailed'));
    } finally {
      setLoading(false);
    }
  }, [jobId, t]);

  return (
    <section className="size-full overflow-auto px-5 py-8">
      <div className="mx-auto max-w-4xl space-y-6">
        <h1 className="text-2xl font-semibold">{t('formFill.title')}</h1>
        <p className="text-sm text-muted-foreground">{t('formFill.subtitle')}</p>

        <div className="rounded-lg border bg-card p-4 space-y-4">
          <div className="flex items-center justify-between">
            <div>
              <div className="font-medium">{t('formFill.step1Title')}</div>
              <div className="text-xs text-muted-foreground break-all">
                {jobId || t('formFill.noJob')}
              </div>
            </div>
            <Button disabled={loading} onClick={handleCreateJob}>
              {t('formFill.actions.createJob')}
            </Button>
          </div>
        </div>

        <div className="rounded-lg border bg-card p-4 space-y-4">
          <div className="font-medium">{t('formFill.step2Title')}</div>
          <p className="text-sm text-muted-foreground">{t('formFill.step2Hint')}</p>
          <input
            type="file"
            multiple
            accept={sourceAccept}
            className="block w-full max-w-xl cursor-pointer text-sm file:mr-4 file:cursor-pointer file:rounded-md file:border file:border-input file:bg-muted file:px-3 file:py-2 file:text-sm file:font-medium"
            onChange={(e) => setSourceFiles(Array.from(e.target.files || []))}
          />
          <div className="text-xs text-muted-foreground">
            {sourceFiles.map((x) => x.name).join(', ') || t('formFill.noSources')}
          </div>
          <Button disabled={loading} onClick={handleUploadSources}>
            {t('formFill.actions.uploadSources')}
          </Button>
        </div>

        <div className="rounded-lg border bg-card p-4 space-y-4">
          <div className="font-medium">{t('formFill.step3Title')}</div>
          <p className="text-sm text-muted-foreground">{t('formFill.step3Hint')}</p>
          <input
            type="file"
            accept={templateAccept}
            className="block w-full max-w-xl cursor-pointer text-sm file:mr-4 file:cursor-pointer file:rounded-md file:border file:border-input file:bg-muted file:px-3 file:py-2 file:text-sm file:font-medium"
            onChange={(e) => setTemplateFile(e.target.files?.[0] || null)}
          />
          <div className="text-xs text-muted-foreground">
            {templateFile?.name || t('formFill.noTemplate')}
          </div>
          <Button disabled={loading} onClick={handleUploadTemplate}>
            {t('formFill.actions.uploadTemplate')}
          </Button>
        </div>

        <div className="rounded-lg border bg-card p-4 space-y-4">
          <div className="font-medium">{t('formFill.step4Title')}</div>
          <div className="space-y-2">
            <label className="text-sm font-medium" htmlFor="form-fill-user-requirements">
              {t('formFill.requirementLabel')}
            </label>
            <p className="text-sm text-muted-foreground">{t('formFill.requirementHint')}</p>
            <Textarea
              id="form-fill-user-requirements"
              value={userRequirements}
              onChange={(e) => setUserRequirements(e.target.value)}
              placeholder={t('formFill.requirementPlaceholder')}
              className="min-h-[120px] max-w-3xl resize-y"
              maxLength={12000}
            />
            <div className="text-xs text-muted-foreground">
              {userRequirements.length}/12000
            </div>
          </div>
          <div className="flex flex-wrap gap-3">
            <Button disabled={!canStart} onClick={handleStart}>
              {t('formFill.actions.start')}
            </Button>
            <Button disabled={loading} onClick={handleDownload}>
              {t('formFill.actions.download')}
            </Button>
            <Button disabled={loading} variant="outline" onClick={handleCleanup}>
              {t('formFill.actions.cleanup')}
            </Button>
          </div>
          {startResult && (
            <div className="space-y-1 text-sm text-muted-foreground">
              <div>
                {t('formFill.result', {
                  elapsed: startResult.elapsedSeconds,
                  limit: startResult.timeoutLimitSeconds,
                })}
              </div>
              {startResult.pipeline?.date_filter_applied &&
                startResult.pipeline.date_range && (
                  <div>
                    {t('formFill.pipelineDateFilter', {
                      start: startResult.pipeline.date_range.start,
                      end: startResult.pipeline.date_range.end,
                      col: startResult.pipeline.date_range.column_hint || '—',
                    })}
                  </div>
                )}
              {typeof startResult.pipeline?.narrative_records_extracted === 'number' &&
                startResult.pipeline.narrative_records_extracted > 0 && (
                  <div>
                    {t('formFill.pipelineNarrative', {
                      n: startResult.pipeline.narrative_records_extracted,
                    })}
                  </div>
                )}
            </div>
          )}
        </div>

      </div>
    </section>
  );
}
